#graphql
  mutation CreateProduct($product: ProductCreateInput!) {
    productCreate(product: $product) {
      product { id title }
      userErrors { field message }
    }
  }

mutation MetafieldsSetAppNamespaceResolution($metafields: [MetafieldsSetInput!]!) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      id
      namespace
      key
      type
      value
    }
    userErrors {
      field
      message
      code
      elementIndex
    }
  }
}

query MetafieldsAppNamespaceProductRead(
  $productId: ID!
  $canonicalNamespace: String!
  $defaultNamespace: String!
  $key: String!
  $defaultKey: String!
) {
  product(id: $productId) {
    id
    canonical: metafield(namespace: $canonicalNamespace, key: $key) {
      id
      namespace
      key
      type
      value
    }
    defaulted: metafield(namespace: $defaultNamespace, key: $defaultKey) {
      id
      namespace
      key
      type
      value
    }
  }
}

